create table wksp_arunext.mtg_scryfall_cards (
    scryfall_id           varchar2(36 char) not null enable,
    oracle_id             varchar2(36 char),
    name                  varchar2(500 char) not null enable,
    lang                  varchar2(10 char) default 'en' not null enable,
    layout                varchar2(50 char),
    released_at           date,
    mana_cost             varchar2(500 char),
    cmc                   number(8, 2),
    type_line             varchar2(500 char),
    oracle_text           clob,
    power                 varchar2(20 char),
    toughness             varchar2(20 char),
    loyalty               varchar2(20 char),
    defense               varchar2(20 char),
    colors_json           json,
    color_identity_json   json,
    keywords_json         json,
    legalities_json       json,
    games_json            json,
    reserved              boolean,
    game_changer          boolean,
    foil                  boolean,
    nonfoil               boolean,
    digital               boolean,
    promo                 boolean,
    reprint               boolean,
    variation             boolean,
    set_id                varchar2(36 char),
    set_code              varchar2(20 char),
    set_name              varchar2(200 char),
    set_type              varchar2(50 char),
    collector_number      varchar2(50 char),
    rarity                varchar2(30 char),
    finishes_json         json,
    artist                varchar2(500 char),
    illustration_id       varchar2(36 char),
    border_color          varchar2(30 char),
    frame                 varchar2(30 char),
    security_stamp        varchar2(30 char),
    full_art              boolean,
    textless              boolean,
    booster               boolean,
    story_spotlight       boolean,
    highres_image         boolean,
    image_status          varchar2(50 char),
    image_small_uri       varchar2(2048 char),
    image_normal_uri      varchar2(2048 char),
    image_large_uri       varchar2(2048 char),
    image_png_uri         varchar2(2048 char),
    image_art_crop_uri    varchar2(2048 char),
    image_border_crop_uri varchar2(2048 char),
    api_uri               varchar2(2048 char),
    scryfall_uri          varchar2(2048 char),
    mtgo_id               number,
    mtgo_foil_id          number,
    tcgplayer_id          number,
    cardmarket_id         number,
    multiverse_ids_json   json,
    raw_scryfall_json     json not null enable,
    scryfall_imported_at  timestamp(6) with time zone default systimestamp not null enable,
    scryfall_updated_at   timestamp(6) with time zone
);

alter table wksp_arunext.mtg_scryfall_cards
    add constraint mtg_scryfall_cards_pk primary key ( scryfall_id )
        using index enable;


